} Implement a custom LogStream listener, this can be used to listen to log entries from both the Notification Plugin and Breez SDK. Swift import BreezSDKLiquid
import XCGLogger class CustomLogListener : Logger { private var logger: XCGLogger init(logger: XCGLogger) { self.logger = logger } func log(l: LogEntry) { switch(l.level) { case "ERROR": logger.error { l.line } break case "WARN": logger.warning { l.line } break case "INFO": logger.info { l.line } break case "DEBUG": logger.debug { l.line } break case "TRACE": logger.verbose { l.line } break default: return } }
